#[derive(Debug, Clone, Default)]
pub struct PostInclude {
    pub author: bool,
}
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PostWithRelations {
    #[serde(flatten)]
    pub data: Post,
    pub author: Option<super::user::User>,
}
impl Post {
    /// Load relations for a batch of records.
    pub(crate) async fn load_relations(
        records: Vec<Post>,
        include: &PostInclude,
        client: &DatabaseClient,
    ) -> Result<Vec<PostWithRelations>, FerriormError> {
        let mut author_map: std::collections::HashMap<String, super::user::User> = std::collections::HashMap::new();
        if include.author {
            let ids: Vec<String> = records.iter().map(|r| r.author_id.clone()).collect();
            if !ids.is_empty() {
                macro_rules! build_in_query {
                    ($db:ty) => {
                        { let mut qb = sqlx::QueryBuilder:: < $db >
                        ::new("SELECT * FROM \"users\" WHERE \"id\" IN ("); let mut sep =
                        qb.separated(", "); for id in & ids { sep.push_bind(id.clone());
                        } qb.push(")"); qb }
                    };
                }
                match client {
                    DatabaseClient::Postgres(pool) => {
                        let mut qb = build_in_query!(sqlx::Postgres);
                        let related_rows: Vec<super::user::User> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        for row in related_rows {
                            author_map.insert(row.id.clone(), row);
                        }
                    }
                    DatabaseClient::Sqlite(pool) => {
                        let mut qb = build_in_query!(sqlx::Sqlite);
                        let related_rows: Vec<super::user::User> = qb
                            .build_query_as()
                            .fetch_all(pool)
                            .await
                            .map_err(FerriormError::from)?;
                        for row in related_rows {
                            author_map.insert(row.id.clone(), row);
                        }
                    }
                }
            }
        }
        let mut results = Vec::with_capacity(records.len());
        for r in records {
            results
                .push(PostWithRelations {
                    author: if include.author {
                        author_map.remove(&r.author_id).map(Some).unwrap_or(None)
                    } else {
                        None
                    },
                    data: r,
                });
        }
        Ok(results)
    }
}
impl<'a> FindManyQuery<'a> {
    pub fn include(self, include: PostInclude) -> FindManyWithIncludeQuery<'a> {
        FindManyWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindManyWithIncludeQuery<'a> {
    inner: FindManyQuery<'a>,
    include: PostInclude,
}
impl<'a> FindManyWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Vec<PostWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let records = FindManyQuery {
            client,
            r#where: self.inner.r#where,
            order_by: self.inner.order_by,
            skip: self.inner.skip,
            take: self.inner.take,
        }
            .exec()
            .await?;
        Post::load_relations(records, &include, client).await
    }
}
impl<'a> FindUniqueQuery<'a> {
    pub fn include(self, include: PostInclude) -> FindUniqueWithIncludeQuery<'a> {
        FindUniqueWithIncludeQuery {
            inner: self,
            include,
        }
    }
}
pub struct FindUniqueWithIncludeQuery<'a> {
    inner: FindUniqueQuery<'a>,
    include: PostInclude,
}
impl<'a> FindUniqueWithIncludeQuery<'a> {
    pub async fn exec(self) -> Result<Option<PostWithRelations>, FerriormError> {
        let include = self.include;
        let client = self.inner.client;
        let record = FindUniqueQuery {
            client,
            r#where: self.inner.r#where,
        }
            .exec()
            .await?;
        match record {
            Some(r) => {
                let mut results = Post::load_relations(vec![r], &include, client).await?;
                Ok(results.pop())
            }
            None => Ok(None),
        }
    }
}
